import{_ as a,o as e,c as r,a7 as i}from"./chunks/framework.C5fSpjcB.js";const b=JSON.parse('{"title":"Combat System","description":"","frontmatter":{},"headers":[],"relativePath":"en/systems/combat.md","filePath":"en/systems/combat.md","lastUpdated":1775394001000}'),o={name:"en/systems/combat.md"};function l(s,t,n,c,d,m){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="combat-system" tabindex="-1">Combat System <a class="header-anchor" href="#combat-system" aria-label="Permalink to &quot;Combat System&quot;">​</a></h1><h2 id="combat-basics" tabindex="-1">Combat Basics <a class="header-anchor" href="#combat-basics" aria-label="Permalink to &quot;Combat Basics&quot;">​</a></h2><p>Morimens uses a real-time combat system where players can control characters to attack, use skills, and dodge.</p><h3 id="basic-actions" tabindex="-1">Basic Actions <a class="header-anchor" href="#basic-actions" aria-label="Permalink to &quot;Basic Actions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td>Normal Attack</td><td>Tap repeatedly for combo attacks</td></tr><tr><td>Skill</td><td>Consume skill points to cast character skills</td></tr><tr><td>Dodge</td><td>Evade enemy attacks; a perfect dodge triggers a time slowdown</td></tr><tr><td>Switch Character</td><td>Swap the active battle character</td></tr><tr><td>Ultimate</td><td>Unleash a powerful ultimate skill when the energy bar is full</td></tr></tbody></table><h3 id="elemental-counters" tabindex="-1">Elemental Counters <a class="header-anchor" href="#elemental-counters" aria-label="Permalink to &quot;Elemental Counters&quot;">​</a></h3><p>Elemental advantage is critical in combat and deals bonus damage against the weak element.</p><h2 id="damage-calculation" tabindex="-1">Damage Calculation <a class="header-anchor" href="#damage-calculation" aria-label="Permalink to &quot;Damage Calculation&quot;">​</a></h2><h3 id="damage-formula" tabindex="-1">Damage Formula <a class="header-anchor" href="#damage-formula" aria-label="Permalink to &quot;Damage Formula&quot;">​</a></h3><p>Base damage calculation involves the following factors:</p><ul><li>ATK</li><li>Skill multiplier</li><li>Elemental advantage bonus</li><li>Crit DMG</li><li>DEF reduction</li><li>Damage increase / decrease buffs</li></ul><h3 id="crit-system" tabindex="-1">Crit System <a class="header-anchor" href="#crit-system" aria-label="Permalink to &quot;Crit System&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Stat</th><th>Description</th></tr></thead><tbody><tr><td>Crit Rate</td><td>Probability of landing a critical hit</td></tr><tr><td>Crit DMG</td><td>Damage multiplier on crit, base 150%</td></tr></tbody></table><h2 id="combat-tips" tabindex="-1">Combat Tips <a class="header-anchor" href="#combat-tips" aria-label="Permalink to &quot;Combat Tips&quot;">​</a></h2><ol><li><strong>Master dodging</strong> - A perfect dodge grants bonus action opportunities</li><li><strong>Chain skills together</strong> - Some character skills create combo effects when linked</li><li><strong>Time your switches</strong> - Switching characters triggers on-entry effects</li><li><strong>Target elemental weaknesses</strong> - Build your team around the enemy&#39;s weak element</li></ol>',15)])])}const u=a(o,[["render",l]]);export{b as __pageData,u as default};
